exercises.solution:
import math

def log2_binomial(n: int, k: int) -> float:
    if k < 0 or k > n:
        return float('-inf')
    if k == 0 or k == n:
        return 0
    return sum(math.log2(n - i) - math.log2(i + 1) for i in range(k))

def prange_complexity(n: int, k: int, t: int) -> float:
    return log2_binomial(n, t) - log2_binomial(n - k, t)

def security_margin(n: int, k: int, t: int, target_bits: int) -> float:
    return prange_complexity(n, k, t) - target_bits

