exercises.solution:
def ct_compare(a: bytes, b: bytes) -> bool:
    if len(a) != len(b):
        return False
    result = 0
    for x, y in zip(a, b):
        result |= x ^ y
    return result == 0

def ct_select(condition: bool, a: bytes, b: bytes) -> bytes:
    mask = -int(condition) & 0xFF
    return bytes((av & mask) | (bv & ~mask & 0xFF) for av, bv in zip(a, b))

def ct_conditional_copy(condition: bool, dest: bytearray, src: bytes) -> None:
    mask = -int(condition) & 0xFF
    for i in range(len(dest)):
        dest[i] = (src[i] & mask) | (dest[i] & ~mask & 0xFF)

