def recommend_mceliece(
    min_classical_bits: int,
    max_pk_mb: float = float('inf')
) -> str:
    params = [
        ('mceliece348864', 143, 0.255),
        ('mceliece460896', 207, 0.512),
        ('mceliece6688128', 272, 1.02),
        ('mceliece8192128', 300, 1.33),
    ]

    for name, bits, pk_mb in params:
        if bits >= min_classical_bits and pk_mb <= max_pk_mb:
            return name

    return 'No suitable parameters (check constraints)'

from typing import Dict

def compare_schemes(security_level: int) -> Dict:
    data = {
        128: {
            'mceliece': {'pk_kb': 255, 'ct_b': 128, 'confidence': 'maximum', 'dfr': 0},
            'bike': {'pk_kb': 1.5, 'ct_b': 1573, 'confidence': 'high', 'dfr': 2**-128}
        },
        256: {
            'mceliece': {'pk_kb': 1020, 'ct_b': 240, 'confidence': 'maximum', 'dfr': 0},
            'bike': {'pk_kb': 5.1, 'ct_b': 5122, 'confidence': 'high', 'dfr': 2**-256}
        }
    }
    return data.get(security_level, {})

def hybrid_recommendation(requirements: Dict) -> str:
    if requirements.get('max_confidence'):
        return 'Classic McEliece alone or Hybrid (McEliece + ML-KEM)'
    elif requirements.get('bandwidth_critical'):
        return 'ML-KEM (smallest overall)'
    else:
        return 'Hybrid ML-KEM + BIKE or ML-KEM + McEliece'
